/**
 * Per-country narrative prose for the report pages.
 *
 * GENERATED by a Sonnet agent workflow grounded ONLY in each country's sourced
 * facts (FATF status, sanctions, WGI governance domains, CPI, enforcement
 * summary) - no invented figures or dates. Committed as static content so the
 * pages stay prerender-safe and SEO-rich with no runtime AI cost.
 *
 * ENGINE-AGNOSTIC (narrative-v2 reconciliation, Wave F1): the prose describes the
 * DRIVERS of each country's risk (WGI governance domains, CPI numbers, FATF /
 * sanctions FACTS, MER dates, qualitative analysis) but never quotes a composite
 * risk score, band label, escalator arithmetic, global-average comparison or
 * governance percentile. Those are products of the v2 scoring engine and drift
 * as it evolves, so tying static prose to them would silently rot and contradict
 * the published number. This de-scoring is what re-enabled the crawler-visible
 * prose in scripts/prerender-seo.ts. The thinNarratives.test.ts guard enforces
 * score-agnosticism across ALL entries; keep it green.
 *
 * Re-run the workflow (scripts/build-country-facts.ts + the narrative agents) to
 * refresh, but keep the output engine-agnostic. Edit by hand only to preserve
 * that property.
 */

export interface CountryNarrative {
  /** One-line summary for the report hero. */
  summary: string;
  /** 3-4 bullets: why this country matters for financial-crime risk. */
  whyItMatters: string[];
  /** A grounded analysis paragraph. */
  analysis: string;
  /** A forward-looking outlook paragraph. */
  outlook: string;
  /** 3-4 key watchpoints for firms. */
  keyWatchpoints: string[];
}

